mapper.insert:
INSERT INTO SCHED(
    USER_ID
    , TITLE
    , SCHED_DATE
    , SCHED_CONTENT
    , CATEGORY
) VALUES (
    #{userId}
    , #{title}
    , #{schedDate}
    , #{schedContent}
    , #{category}
)

mapper.update:
UPDATE SCHED
SET TITLE = #{title}
    , SCHED_DATE = #{schedDate}
    , SCHED_CONTENT = #{schedContent}
    , CATEGORY = #{category}
WHERE SCHED_ID = #{schedId}

UPDATE SCHED
SET IS_COMPLETED = #{isCompleted}
WHERE SCHED_ID = #{schedId}
